using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tool that fetches data from an external API using an injected HttpClient.
/// </summary>
internal class ApiFetchTool(HttpClient httpClient)
{
    [McpServerTool(Name = "fetch_api")]
    [Description("Fetches JSON data from the specified URL and returns it as formatted text.")]
    public async Task<string> FetchApiAsync(
        [Description("The absolute URL to fetch (must be http or https).")] string url,
        CancellationToken cancellationToken = default)
    {
        if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)
            || (uri.Scheme != "https" && uri.Scheme != "http"))
        {
            return "Error: Please provide a valid http(s) URL.";
        }

        var response = await httpClient.GetAsync(uri, cancellationToken);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadAsStringAsync(cancellationToken);

        // Pretty-print if the response is valid JSON; return raw text otherwise.
        try
        {
            var doc = JsonDocument.Parse(body);
            return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (JsonException)
        {
            return body;
        }
    }
}

using System.ComponentModel;
using ModelContextProtocol;
using ModelContextProtocol.Server;

/// <summary>
/// Prompt template that generates a summarization request for an LLM.
/// </summary>
internal class SummarizationPrompt
{
    [McpServerPrompt(Name = "summarize")]
    [Description("Generates a prompt that asks an LLM to summarize the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional desired length (e.g. '2 sentences', 'one paragraph').")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following text in {maxLength}:"
            : "Summarize the following text concisely:";

        return
        [
            new(Role.User, new Content
            {
                Type = "text",
                Text = $"{instruction}\n\n{text}"
            })
        ];
    }
}

